  @case 'arp over a span with no sounding notes emits nothing'  [harness]  @ 720-725
  @case 'fx region: the producer hands the generator notes/pas/ccs/ats input streams'  [harness]  @ 731-761
  @case 'fx region: an OPEN member clips to the next same-lane onset, not the window end'  [harness]  @ 765-788
  @case 'fx region: host.pb carries authored pb breakpoints, excluding absorber fakes'  [harness]  @ 792-816
